"  Future<void> _getUserLocation({bool forceRefresh = false}) async {
    setState(() {
      _loadingLocation = true;
    });
    try {
      Position? position;

      // 1. Check if location services are enabled
      bool serviceEnabled = await Geolocator.isLocationServiceEnabled();
      LocationPermission permission = await Geolocator.checkPermission();

      // 2. Request permission if denied
      if (permission == LocationPermission.denied) {
        permission = await Geolocator.requestPermission();
      }

      // 3. Try to get cached last known position first (INSTANT - takes milliseconds)
      if (serviceEnabled &&
          (permission == LocationPermission.whileInUse ||
              permission == LocationPermission.always)) {
        try {
          position = await Geolocator.getLastKnownPosition();
          if (position != null) {
            debugPrint("Successfully fetched cached last known GPS: ${position.latitude}, ${position.longitude}");
          }
        } catch (e) {
          debugPrint("Failed to fetch cached GPS: $e");
        }

        // If no cached position is available, fetch fresh live position quickly with medium accuracy
        if (position == null) {
          try {
            debugPrint("Attempting to get fresh live GPS location...");
            position = await Geolocator.getCurrentPosition(
              desiredAccuracy: LocationAccuracy.medium, // Medium accuracy is much faster than high
              timeLimit: const Duration(seconds: 4), // Fast 4s timeout
            );
            debugPrint("Successfully fetched live GPS: ${position.latitude}, ${position.longitude}");
          } catch (e) {
            debugPrint("Failed to fetch fresh live GPS: $e.");
          }
        }
      }"

